def t_cdf(t, df):
    """
    Cumulative distribution function for t-distribution.
    Uses the relationship: t-distribution CDF = incomplete regularized beta function.
    """
    from math import gamma, pi, sqrt

    def regularized_incomplete_beta(a, b, x):
        """Approximate regularized incomplete beta function I_x(a, b)"""
        if x <= 0:
            return 0.0
        if x >= 1:
            return 1.0

        # Use Taylor series approximation for small x
        if x < 0.5:
            numerator = sum(
                math.comb(b - 1 + k, k) * (x ** (a + k)) / (a + k)
                for k in range(50)
            )
            denominator = sum(
                math.comb(b - 1 + k, k) * (x ** (a + k))
                for k in range(50)
            )
            return numerator / denominator if denominator != 0 else 0
        else:
            # For x > 0.5, use complementary form
            return 1.0 - regularized_incomplete_beta(b, a, 1 - x)

    # t-distribution: P(T ≤ t) = I_{x}(df/2, 1/2) where x = df/(df+t²)
    t_abs = abs(t)
    x = df / (df + t_abs ** 2)

    if t >= 0:
        return regularized_incomplete_beta(df / 2, 0.5, x)
    else:
        return 1.0 - regularized_incomplete_beta(df / 2, 0.5, x)

