#!/usr/bin/env python3
"""
Reads config.json and data.csv, infers a SQL schema, generates INSERT
statements, saves everything to schema.sql, and prints the result.
"""

import csv
import json


# ── helpers ──────────────────────────────────────────────────────────────────

def infer_sql_type(values: list[str]) -> str:
    """Return the narrowest SQL type that fits all non-empty values."""
    non_empty = [v for v in values if v.strip()]
    if not non_empty:
        return "TEXT"

    # Try INTEGER first
    try:
        for v in non_empty:
            int(v)
        return "INTEGER"
    except ValueError:
        pass

    # Try REAL next
    try:
        for v in non_empty:
            float(v)
        return "REAL"
    except ValueError:
        pass

    return "TEXT"


def escape_value(value: str, sql_type: str) -> str:
    """Format a CSV cell as a SQL literal."""
    stripped = value.strip()
    if stripped == "":
        return "NULL"
    if sql_type == "INTEGER":
        return str(int(stripped))
    if sql_type == "REAL":
        return str(float(stripped))
    # TEXT: escape single quotes by doubling them
    escaped = stripped.replace("'", "''")
    return f"'{escaped}'"


# ── main ─────────────────────────────────────────────────────────────────────

def main() -> None:
    # 1. Load config ──────────────────────────────────────────────────────────
    with open("config.json", encoding="utf-8") as fh:
        config = json.load(fh)

    table_name = config["database"]["name"]

    # 2. Load CSV ─────────────────────────────────────────────────────────────
    with open("data.csv", encoding="utf-8", newline="") as fh:
        reader = csv.DictReader(fh)
        columns = reader.fieldnames or []
        rows = [row for row in reader if any(v.strip() for v in row.values())]

    if not columns:
        raise ValueError("data.csv has no header row.")

    # 3. Infer column types ───────────────────────────────────────────────────
    col_values: dict[str, list[str]] = {col: [] for col in columns}
    for row in rows:
        for col in columns:
            col_values[col].append(row[col])

    col_types: dict[str, str] = {
        col: infer_sql_type(col_values[col]) for col in columns
    }

    # 4. Build SQL ────────────────────────────────────────────────────────────
    lines: list[str] = []

    # CREATE TABLE
    lines.append(f"CREATE TABLE IF NOT EXISTS {table_name} (")
    col_defs = [f"    {col} {col_types[col]}" for col in columns]
    lines.append(",\n".join(col_defs))
    lines.append(");")
    lines.append("")

    # INSERT statements
    col_list = ", ".join(columns)
    for row in rows:
        values = ", ".join(
            escape_value(row[col], col_types[col]) for col in columns
        )
        lines.append(f"INSERT INTO {table_name} ({col_list}) VALUES ({values});")

    sql = "\n".join(lines)

    # 5. Save and print ───────────────────────────────────────────────────────
    with open("schema.sql", "w", encoding="utf-8") as fh:
        fh.write(sql + "\n")

    print(sql)


if __name__ == "__main__":
    main()

"""
Reads config.json and data.csv, generates a SQL schema and INSERT statements,
saves the result to schema.sql, and prints it to stdout.
"""

import csv
import json
import re
from pathlib import Path


# ── helpers ──────────────────────────────────────────────────────────────────

def infer_sql_type(values: list[str]) -> str:
    """
    Infer the most appropriate SQL column type from a list of raw string values.
    Priority: INTEGER → REAL → TEXT (BOOLEAN is mapped to INTEGER).
    NULL / empty strings are skipped so they don't pollute the inference.
    """
    non_empty = [v for v in values if v.strip() != ""]
    if not non_empty:
        return "TEXT"

    def is_integer(v: str) -> bool:
        try:
            int(v)
            return True
        except ValueError:
            return False

    def is_real(v: str) -> bool:
        try:
            float(v)
            return True
        except ValueError:
            return False

    bool_tokens = {"true", "false", "yes", "no", "1", "0"}

    if all(v.strip().lower() in bool_tokens for v in non_empty):
        return "INTEGER"          # store booleans as 0/1

    if all(is_integer(v.strip()) for v in non_empty):
        return "INTEGER"

    if all(is_real(v.strip()) for v in non_empty):
        return "REAL"

    return "TEXT"


def quote_identifier(name: str) -> str:
    """Wrap a column/table name in double-quotes (handles reserved words & spaces)."""
    return f'"{name}"'


def escape_sql_value(raw: str, sql_type: str) -> str:
    """
    Return the SQL literal for a value:
      - empty string  → NULL
      - INTEGER/REAL  → bare number
      - TEXT          → single-quoted string with inner quotes escaped
    """
    stripped = raw.strip()

    if stripped == "":
        return "NULL"

    if sql_type == "INTEGER":
        # Normalise booleans → 0/1
        if stripped.lower() in {"true", "yes"}:
            return "1"
        if stripped.lower() in {"false", "no"}:
            return "0"
        return str(int(stripped))

    if sql_type == "REAL":
        return str(float(stripped))

    # TEXT — escape single quotes by doubling them
    escaped = stripped.replace("'", "''")
    return f"'{escaped}'"


def sanitise_column_name(name: str) -> str:
    """Replace whitespace / special chars that are problematic in identifiers."""
    return re.sub(r"\s+", "_", name.strip())


# ── main logic ────────────────────────────────────────────────────────────────

def load_config(path: str = "config.json") -> dict:
    config_path = Path(path)
    if not config_path.exists():
        raise FileNotFoundError(f"Config file not found: {path}")
    with config_path.open() as fh:
        return json.load(fh)


def load_csv(path: str = "data.csv") -> tuple[list[str], list[list[str]]]:
    """Return (headers, rows) where every cell is a raw string."""
    csv_path = Path(path)
    if not csv_path.exists():
        raise FileNotFoundError(f"CSV file not found: {path}")
    with csv_path.open(newline="", encoding="utf-8") as fh:
        reader = csv.reader(fh)
        headers = [sanitise_column_name(h) for h in next(reader)]
        rows = list(reader)
    return headers, rows


def build_sql(table_name: str, headers: list[str], rows: list[list[str]]) -> str:
    """Assemble the CREATE TABLE statement and all INSERT statements."""
    # Infer a SQL type for every column from the full column's data
    col_types = {
        col: infer_sql_type([row[i] for row in rows if i < len(row)])
        for i, col in enumerate(headers)
    }

    # ── CREATE TABLE ──────────────────────────────────────────────────────────
    col_defs = ",\n    ".join(
        f"{quote_identifier(col)} {col_types[col]}"
        for col in headers
    )
    create_stmt = (
        f"CREATE TABLE IF NOT EXISTS {quote_identifier(table_name)} (\n"
        f"    {col_defs}\n"
        f");"
    )

    # ── INSERT statements ─────────────────────────────────────────────────────
    col_list = ", ".join(quote_identifier(col) for col in headers)
    insert_lines = []
    for row in rows:
        # Pad short rows with empty strings
        padded = row + [""] * (len(headers) - len(row))
        values = ", ".join(
            escape_sql_value(padded[i], col_types[headers[i]])
            for i in range(len(headers))
        )
        insert_lines.append(
            f"INSERT INTO {quote_identifier(table_name)} ({col_list}) VALUES ({values});"
        )

    inserts = "\n".join(insert_lines)
    return f"{create_stmt}\n\n{inserts}"


def main() -> None:
    # 1. Load inputs
    config = load_config("config.json")

    try:
        table_name = config["database"]["name"]
    except KeyError as exc:
        raise KeyError(
            "config.json must contain a 'database.name' key. "
            f"Missing key: {exc}"
        ) from exc

    headers, rows = load_csv("data.csv")

    if not headers:
        raise ValueError("data.csv has no columns.")

    print(f"Table name  : {table_name}")
    print(f"Columns     : {', '.join(headers)}")
    print(f"Rows        : {len(rows)}")
    print("-" * 60)

    # 2. Generate SQL
    sql = build_sql(table_name, headers, rows)

    # 3. Save to file
    output_path = Path("schema.sql")
    output_path.write_text(sql, encoding="utf-8")
    print(f"Saved to    : {output_path.resolve()}")
    print("=" * 60)

    # 4. Print the SQL
    print(sql)


if __name__ == "__main__":
    main()

