    NULL / empty strings are skipped so they don't pollute the inference.
    """
    non_empty = [v for v in values if v.strip() != ""]
    if not non_empty:
        return "TEXT"

    def is_integer(v: str) -> bool:
        try:
            int(v)
            return True
        except ValueError:
            return False

    def is_real(v: str) -> bool:
        try:
            float(v)
            return True
        except ValueError:
            return False

    bool_tokens = {"true", "false", "yes", "no", "1", "0"}

    if all(v.strip().lower() in bool_tokens for v in non_empty):
        return "INTEGER"          # store booleans as 0/1

    if all(is_integer(v.strip()) for v in non_empty):
        return "INTEGER"

    if all(is_real(v.strip()) for v in non_empty):
        return "REAL"

    return "TEXT"


def quote_identifier(name: str) -> str:
    """Wrap a column/table name in double-quotes (handles reserved words & spaces)."""
    return f'"{name}"'


def escape_sql_value(raw: str, sql_type: str) -> str:
    """
    Return the SQL literal for a value:
      - empty string  → NULL
      - INTEGER/REAL  → bare number
      - TEXT          → single-quoted string with inner quotes escaped
    """
    stripped = raw.strip()

    if stripped == "":
        return "NULL"

    if sql_type == "INTEGER":
        # Normalise booleans → 0/1
        if stripped.lower() in {"true", "yes"}:
            return "1"
        if stripped.lower() in {"false", "no"}:
            return "0"
        return str(int(stripped))

    if sql_type == "REAL":
        return str(float(stripped))

    # TEXT — escape single quotes by doubling them
    escaped = stripped.replace("'", "''")
    return f"'{escaped}'"


def sanitise_column_name(name: str) -> str:
    """Replace whitespace / special chars that are problematic in identifiers."""
    return re.sub(r"\s+", "_", name.strip())


# ── main logic ────────────────────────────────────────────────────────────────

def load_config(path: str = "config.json") -> dict:
    config_path = Path(path)
    if not config_path.exists():
        raise FileNotFoundError(f"Config file not found: {path}")
    with config_path.open() as fh:
        return json.load(fh)


def load_csv(path: str = "data.csv") -> tuple[list[str], list[list[str]]]:
    """Return (headers, rows) where every cell is a raw string."""
    csv_path = Path(path)
    if not csv_path.exists():
        raise FileNotFoundError(f"CSV file not found: {path}")
    with csv_path.open(newline="", encoding="utf-8") as fh:
        reader = csv.reader(fh)
        headers = [sanitise_column_name(h) for h in next(reader)]
        rows = list(reader)
    return headers, rows


def build_sql(table_name: str, headers: list[str], rows: list[list[str]]) -> str:
    """Assemble the CREATE TABLE statement and all INSERT statements."""
    # Infer a SQL type for every column from the full column's data
    col_types = {
        col: infer_sql_type([row[i] for row in rows if i < len(row)])
        for i, col in enumerate(headers)
    }

    # ── CREATE TABLE ──────────────────────────────────────────────────────────
    col_defs = ",\n    ".join(
        f"{quote_identifier(col)} {col_types[col]}"
        for col in headers
    )
    create_stmt = (
        f"CREATE TABLE IF NOT EXISTS {quote_identifier(table_name)} (\n"
        f"    {col_defs}\n"
        f");"
    )

    # ── INSERT statements ─────────────────────────────────────────────────────
    col_list = ", ".join(quote_identifier(col) for col in headers)
    insert_lines = []
    for row in rows:
        # Pad short rows with empty strings
        padded = row + [""] * (len(headers) - len(row))
        values = ", ".join(
            escape_sql_value(padded[i], col_types[headers[i]])
            for i in range(len(headers))
        )
        insert_lines.append(
            f"INSERT INTO {quote_identifier(table_name)} ({col_list}) VALUES ({values});"
        )

    inserts = "\n".join(insert_lines)
    return f"{create_stmt}\n\n{inserts}"


def main() -> None:
    # 1. Load inputs
    config = load_config("config.json")

    try:
        table_name = config["database"]["name"]
    except KeyError as exc:
        raise KeyError(
            "config.json must contain a 'database.name' key. "
            f"Missing key: {exc}"
        ) from exc

    headers, rows = load_csv("data.csv")

    if not headers:
        raise ValueError("data.csv has no columns.")

    print(f"Table name  : {table_name}")
    print(f"Columns     : {', '.join(headers)}")
    print(f"Rows        : {len(rows)}")
    print("-" * 60)

    # 2. Generate SQL
    sql = build_sql(table_name, headers, rows)

    # 3. Save to file
    output_path = Path("schema.sql")
    output_path.write_text(sql, encoding="utf-8")
    print(f"Saved to    : {output_path.resolve()}")
    print("=" * 60)

    # 4. Print the SQL
    print(sql)


if __name__ == "__main__":
    main()

